def deep_merge(base: dict, updates: dict) -> dict:
    """Recursively merge updates into base dict."""
    for key, value in updates.items():
        if key in base and isinstance(base[key], dict) and isinstance(value, dict):
            deep_merge(base[key], value)
        else:
            base[key] = value
    return base


def main():
    for lang_code, translations in TRANSLATIONS.items():
        fpath = I18N_DIR / f'{lang_code}.json'
        if not fpath.exists():
            print(f"SKIP {lang_code}: file not found")
            continue

        data = json.loads(fpath.read_text(encoding='utf-8'))
        deep_merge(data, translations)
        
        # Validate JSON
        out = json.dumps(data, ensure_ascii=False, indent=2)
        json.loads(out)  # validate
        
        fpath.write_text(out + '\n', encoding='utf-8')
        
        # Count keys
        total_keys = sum(len(v) if isinstance(v, dict) else 1 for v in data.values())
        print(f"OK {lang_code}.json - {total_keys} top-level sections updated")

    print("\nAll language packs updated!")


if __name__ == '__main__':
    main()
